#!/usr/bin/env python3
"""Apply Update v6 - Link client to room/bed"""
import base64, os

PROJECT = os.path.expanduser("~/Desktop/dream-abroad")

files = {
    "backend/routers/clients.py": "",
    "frontend/src/pages/Clients.tsx": "",
}

for rel_path, b64 in files.items():
    full = os.path.join(PROJECT, rel_path)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, "w") as f:
        f.write(base64.b64decode(b64).decode())
    print(f"Updated: {rel_path}")

print("\nDone! Restart backend: lsof -ti:8000 | xargs kill -9 && uvicorn main:app --reload")
